/**
 * @summary Get all past contracts for the current user (Dashboard)
 */
export const getGetContractHistoryUrl = () => {
  return `/api/contracts/history`;
};

export const getContractHistory = async (
  options?: RequestInit,
): Promise<ContractHistoryResponse> => {
  return customFetch<ContractHistoryResponse>(getGetContractHistoryUrl(), {
    ...options,
    method: "GET",
  });
};

export const getGetContractHistoryQueryKey = () => {
  return [`/api/contracts/history`] as const;
};

export const getGetContractHistoryQueryOptions = <
  TData = Awaited<ReturnType<typeof getContractHistory>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getContractHistory>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetContractHistoryQueryKey();

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getContractHistory>>
  > = ({ signal }) => getContractHistory({ signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getContractHistory>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetContractHistoryQueryResult = NonNullable<
  Awaited<ReturnType<typeof getContractHistory>>
>;
export type GetContractHistoryQueryError = ErrorType<unknown>;

/**
 * @summary Get all past contracts for the current user (Dashboard)
 */

export function useGetContractHistory<
  TData = Awaited<ReturnType<typeof getContractHistory>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getContractHistory>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetContractHistoryQueryOptions(options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary Get a single contract with full detail
 */
export const getGetContractUrl = (contractId: string) => {
  return `/api/contracts/${contractId}`;
};

export const getContract = async (
  contractId: string,
  options?: RequestInit,
): Promise<ContractDetailResponse> => {
  return customFetch<ContractDetailResponse>(getGetContractUrl(contractId), {
    ...options,
    method: "GET",
  });
};

export const getGetContractQueryKey = (contractId: string) => {
  return [`/api/contracts/${contractId}`] as const;
};

export const getGetContractQueryOptions = <
  TData = Awaited<ReturnType<typeof getContract>>,
  TError = ErrorType<ErrorResponse>,
>(
  contractId: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getContract>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetContractQueryKey(contractId);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getContract>>> = ({
    signal,
  }) => getContract(contractId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!contractId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getContract>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetContractQueryResult = NonNullable<
  Awaited<ReturnType<typeof getContract>>
>;
export type GetContractQueryError = ErrorType<ErrorResponse>;

/**
 * @summary Get a single contract with full detail
 */

export function useGetContract<
  TData = Awaited<ReturnType<typeof getContract>>,
  TError = ErrorType<ErrorResponse>,
>(
  contractId: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getContract>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetContractQueryOptions(contractId, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
